q=A.dt(A.a([A.E("\ud83d\udc1f","braised-fish",A.e(["zh","\u7ea2\u70e7\u9c7c","en","Braised Fish"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9c7c\uff08\u9ca4\u9c7c\u6216\u8349\u9c7c\uff09\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u7cd6\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9c7c\u6d17\u51c0\u4e24\u9762\u5212\u5200\uff0c\u7528\u6599\u9152\u548c\u76d0\u814c\u523615\u5206\u949f\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u714e\u9c7c\u81f3\u4e24\u9762\u91d1\u9ec4\u30023. \u52a0\u8471\u59dc\u849c\u7092\u9999\uff0c\u52a0\u5165\u9171\u6cb9\u3001\u6599\u9152\u548c\u7cd6\u8c03\u5473\u30024. \u52a0\u6c34\u7096\u716e20\u5206\u949f\u30025. \u5927\u706b\u6536\u6c41\uff0c\u6492\u8471\u82b1\u5373\u53ef\u3002","en","Ingredients: Fish (carp or grass carp), green onions, ginger, garlic, soy sauce, cooking wine, sugar, cooking oil\nMethod: 1. Clean fish and score both sides, marinate with cooking wine and salt for 15 minutes. 2. Heat oil in a pan, fry fish until golden on both sides. 3. Add green onions, ginger, and garlic, saut\xe9 until fragrant, then add soy sauce, cooking wine, and sugar. 4. Add water and simmer for 20 minutes. 5. Reduce sauce over high heat, sprinkle with green onions, and serve."],a6,a6),95,h),A.E("\ud83e\uddaa","stir-fried-oysters-peppers",A.e(["zh","\u8fa3\u6912\u7092\u7261\u86ce\u8089","en","Stir-fried Oysters with Peppers"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u7261\u86ce\u8089\u3001\u9752\u6912\u3001\u7ea2\u6912\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u7261\u86ce\u8089\u6d17\u51c0\u6ca5\u5e72\uff0c\u9752\u6912\u548c\u7ea2\u6912\u5207\u4e1d\uff0c\u8471\u59dc\u5207\u672b\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7206\u9999\u8471\u59dc\u30023. \u653e\u5165\u7261\u86ce\u8089\u7ffb\u7092\u81f3\u53d8\u8272\u30024. \u52a0\u5165\u8fa3\u6912\u4e1d\u5feb\u901f\u7092\u5300\uff0c\u52a0\u9171\u6cb9\u548c\u76d0\u8c03\u5473\u5373\u53ef\u3002","en","Ingredients: Oyster meat, green peppers, red peppers, green onions, ginger, soy sauce, salt, cooking oil\nMethod: 1. Rinse and drain oyster meat, shred green and red peppers, mince green onions and ginger. 2. Heat oil in a pan, saut\xe9 green onions and ginger. 3. Add oyster meat and stir-fry until it changes color. 4. Add pepper shreds, stir-fry quickly, season with soy sauce and salt, and serve."],a6,a6),92,h),A.E("\ud83c\udf64","kung-pao-shrimp-cashew-celery",A.e(["zh","\u5bab\u4fdd\u8170\u679c\u82b9\u83dc\u7092\u867e\u4ec1","en","Kung Pao Shrimp with Cashew and Celery"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u867e\u4ec1\u3001\u8170\u679c\u3001\u82b9\u83dc\u3001\u5e72\u8fa3\u6912\u3001\u82b1\u6912\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u7cd6\u3001\u918b\u3001\u6dc0\u7c89\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u867e\u4ec1\u7528\u6dc0\u7c89\u814c\u523610\u5206\u949f\uff0c\u82b9\u83dc\u5207\u6bb5\u30022. \u8170\u679c\u70b8\u81f3\u91d1\u9ec4\u635e\u51fa\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u9999\u5e72\u8fa3\u6912\u548c\u82b1\u6912\uff0c\u653e\u5165\u8471\u59dc\u7206\u9999\u30024. \u52a0\u867e\u4ec1\u7092\u81f3\u53d8\u8272\uff0c\u518d\u653e\u5165\u82b9\u83dc\u7ffb\u7092\u30025. \u8c03\u9171\u6c41\uff08\u9171\u6cb9\u3001\u7cd6\u3001\u918b\uff09\u5012\u5165\uff0c\u52a0\u5165\u8170\u679c\u7092\u5300\u5373\u53ef\u3002","en","Ingredients: Shrimp, cashews, celery, dried chilies, Sichuan peppercorns, green onions, ginger, soy sauce, sugar, vinegar, cornstarch, cooking oil\nMethod: 1. Marinate shrimp with cornstarch for 10 minutes, cut celery into segments. 2. Fry cashews until golden and remove. 3. Heat oil in a pan, saut\xe9 dried chilies and peppercorns, then add green onions and ginger. 4. Add shrimp and stir-fry until they change color, then add celery and stir-fry. 5. Mix sauce (soy sauce, sugar, vinegar), pour in, add cashews, stir well, and serve."],a6,a6),96,h),A.E("\ud83e\udd90","braised-shrimp",A.e(["zh","\u6cb9\u7116\u5927\u867e","en","Braised Shrimp"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u5927\u867e\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u7cd6\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u5927\u867e\u526a\u987b\u6d17\u51c0\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u653e\u5165\u5927\u867e\u714e\u81f3\u4e24\u9762\u53d8\u7ea2\u30023. \u52a0\u8471\u59dc\u849c\u7092\u9999\uff0c\u52a0\u5165\u9171\u6cb9\u3001\u6599\u9152\u548c\u7cd6\u8c03\u5473\u30024. \u52a0\u5c11\u8bb8\u6c34\u7116\u716e5\u5206\u949f\u30025. \u5927\u706b\u6536\u6c41\u5373\u53ef\u3002","en","Ingredients: Large shrimp, green onions, ginger, garlic, soy sauce, cooking wine, sugar, cooking oil\nMethod: 1. Trim and rinse shrimp. 2. Heat oil in a pan, fry shrimp until both sides turn red. 3. Add green onions, ginger, and garlic, saut\xe9 until fragrant, then add soy sauce, cooking wine, and sugar. 4. Add a little water and braise for 5 minutes. 5. Reduce sauce over high heat and serve."],a6,a6),88,h),A.E(a1,"steamed-seafood-garlic",A.e(["zh","\u849c\u84c9\u7c89\u4e1d/\u751f\u869d/\u867e/\u6247\u8d1d","en","Steamed Seafood with Garlic and Vermicelli"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u7c89\u4e1d\u3001\u751f\u869d/\u867e/\u6247\u8d1d\u3001\u5927\u849c\u3001\u8471\u3001\u9171\u6cb9\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u7c89\u4e1d\u6ce1\u8f6f\u94fa\u5728\u76d8\u5e95\uff0c\u751f\u869d/\u867e/\u6247\u8d1d\u6d17\u51c0\u653e\u4e0a\u30022. \u5927\u849c\u5207\u672b\uff0c\u70ed\u6cb9\u7092\u9999\uff0c\u52a0\u5165\u9171\u6cb9\u8c03\u5473\u30023. \u5c06\u849c\u84c9\u9171\u6dcb\u5728\u6d77\u9c9c\u4e0a\u30024. \u6c34\u5f00\u540e\u84b88-10\u5206\u949f\u30025. \u6492\u8471\u82b1\u51fa\u9505\u3002","en","Ingredients: Vermicelli, oysters/shrimp/scallops, garlic, green onions, soy sauce, cooking oil\nMethod: 1. Soak vermicelli until soft and place at the bottom of a dish, rinse oysters/shrimp/scallops and arrange on top. 2. Mince garlic, heat oil and saut\xe9 until fragrant, add soy sauce to season. 3. Pour garlic sauce over the seafood. 4. Steam for 8-10 minutes after water boils. 5. Sprinkle with green onions and serve."],a6,a6),90,h),A.E("\ud83e\udd91","stir-fried-squid-rings",A.e(["zh","\u59dc\u849c\u9c7f\u9c7c\u5708","en","Stir-fried Squid Rings with Ginger and Garlic"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9c7f\u9c7c\u3001\u59dc\u3001\u849c\u3001\u8471\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9c7f\u9c7c\u5207\u5708\uff0c\u7528\u6599\u9152\u814c\u523610\u5206\u949f\u30022. \u59dc\u849c\u5207\u672b\uff0c\u8471\u5207\u6bb5\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7206\u9999\u59dc\u849c\u30024. \u653e\u5165\u9c7f\u9c7c\u5708\u5feb\u901f\u7ffb\u7092\u81f3\u5377\u66f2\u30025. \u52a0\u9171\u6cb9\u548c\u76d0\u8c03\u5473\uff0c\u6492\u8471\u6bb5\u51fa\u9505\u3002","en","Ingredients: Squid, ginger, garlic, green onions, soy sauce, cooking wine, salt, cooking oil\nMethod: 1. Cut squid into rings, marinate with cooking wine for 10 minutes. 2. Mince ginger and garlic, cut green onions into segments. 3. Heat oil in a pan, saut\xe9 ginger and garlic. 4. Add squid rings and stir-fry quickly until they curl. 5. Season with soy sauce and salt, sprinkle with green onions, and serve."],a6,a6),d,e),A.E(f,"sour-cabbage-fish",A.e(["zh","\u9178\u83dc\u9c7c","en","Sour Cabbage Fish"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9c7c\u7247\uff08\u8349\u9c7c\u6216\u9c88\u9c7c\uff09\u3001\u9178\u83dc\u3001\u6ce1\u6912\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u9e21\u86cb\u6e05\u3001\u6dc0\u7c89\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9c7c\u7247\u7528\u86cb\u6e05\u548c\u6dc0\u7c89\u814c\u523615\u5206\u949f\u30022. \u9178\u83dc\u5207\u6bb5\uff0c\u6ce1\u6912\u5207\u788e\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u9999\u8471\u59dc\u849c\u548c\u6ce1\u6912\uff0c\u52a0\u5165\u9178\u83dc\u7092\u5300\u30024. \u52a0\u6c34\u716e\u5f00\uff0c\u4e0b\u9c7c\u7247\u716e\u81f3\u53d8\u767d\u30025. \u52a0\u76d0\u8c03\u5473\u5373\u53ef\u3002","en","Ingredients: Fish fillets (grass carp or bass), pickled cabbage, pickled peppers, green onions, ginger, garlic, egg white, cornstarch, cooking oil\nMethod: 1. Marinate fish fillets with egg white and cornstarch for 15 minutes. 2. Cut pickled cabbage into segments, chop pickled peppers. 3. Heat oil in a pan, saut\xe9 green onions, ginger, garlic, and pickled peppers, then add pickled cabbage and stir-fry. 4. Add water and bring to a boil, add fish fillets and cook until they turn white. 5. Season with salt and serve."],a6,a6),85,h),A.E(g,"spicy-fish",A.e(["zh","\u9ebb\u8fa3\u9c7c","en","Spicy Fish"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9c7c\uff08\u9ca4\u9c7c\u6216\u8349\u9c7c\uff09\u3001\u5e72\u8fa3\u6912\u3001\u82b1\u6912\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u8c46\u74e3\u9171\u3001\u9171\u6cb9\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9c7c\u6d17\u51c0\u5207\u5757\uff0c\u7528\u6599\u9152\u814c\u523615\u5206\u949f\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u714e\u9c7c\u5757\u81f3\u4e24\u9762\u91d1\u9ec4\uff0c\u76db\u51fa\u30023. \u9505\u4e2d\u7559\u6cb9\uff0c\u7092\u9999\u5e72\u8fa3\u6912\u3001\u82b1\u6912\u548c\u8c46\u74e3\u9171\u30024. \u52a0\u8471\u59dc\u849c\u7092\u9999\uff0c\u653e\u5165\u9c7c\u5757\u52a0\u6c34\u716e10\u5206\u949f\u30025. \u52a0\u9171\u6cb9\u8c03\u5473\uff0c\u5927\u706b\u6536\u6c41\u5373\u53ef\u3002","en","Ingredients: Fish (carp or grass carp), dried chilies, Sichuan peppercorns, green onions, ginger, garlic, bean paste, soy sauce, cooking oil\nMethod: 1. Clean and cut fish into chunks, marinate with cooking wine for 15 minutes. 2. Heat oil in a pan, fry fish chunks until golden on both sides, then remove. 3. Leave some oil in the pan, saut\xe9 dried chilies, peppercorns, and bean paste. 4. Add green onions, ginger, and garlic, saut\xe9 until fragrant, then add fish chunks and water, cook for 10 minutes. 5. Season with soy sauce, reduce sauce over high heat, and serve."],a6,a6),d,e)],a9),"seafood",q)
