p=A.dt(A.a([A.E("\ud83e\udd64","coke-chicken-wings",A.e(["zh","\u53ef\u4e50\u9e21\u7fc5","en","Coke Chicken Wings"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u7fc5\u3001\u53ef\u4e50\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u7fc5\u6d17\u51c0\u4e24\u9762\u5212\u5200\uff0c\u7528\u6599\u9152\u814c\u523610\u5206\u949f\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u714e\u9e21\u7fc5\u81f3\u4e24\u9762\u91d1\u9ec4\u30023. \u52a0\u8471\u59dc\u7092\u9999\uff0c\u52a0\u5165\u9171\u6cb9\u548c\u53ef\u4e50\u6ca1\u8fc7\u9e21\u7fc5\u30024. \u5927\u706b\u70e7\u5f00\u540e\u5c0f\u706b\u709620\u5206\u949f\u30025. \u5927\u706b\u6536\u6c41\u5373\u53ef\u3002","en","Ingredients: Chicken wings, cola, green onions, ginger, soy sauce, cooking wine, salt, cooking oil\nMethod: 1. Rinse chicken wings and score both sides, marinate with cooking wine for 10 minutes. 2. Heat oil in a pan, fry wings until golden on both sides. 3. Add green onions and ginger, saut\xe9 until fragrant, then add soy sauce and cola to cover the wings. 4. Bring to a boil, then simmer for 20 minutes. 5. Reduce sauce over high heat and serve."],a6,a6),95,h),A.E(a4,"chicken-wings-pot",A.e(["zh","\u9e21\u7fc5\u7172","en","Chicken Wings Pot"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u7fc5\u3001\u571f\u8c46\u3001\u9752\u6912\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u7cd6\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u7fc5\u7528\u6599\u9152\u548c\u9171\u6cb9\u814c\u523620\u5206\u949f\uff0c\u571f\u8c46\u5207\u5757\uff0c\u9752\u6912\u5207\u6bb5\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u714e\u9e21\u7fc5\u81f3\u91d1\u9ec4\u30023. \u52a0\u8471\u59dc\u849c\u7092\u9999\uff0c\u653e\u5165\u571f\u8c46\u548c\u9752\u6912\u7ffb\u7092\u30024. \u52a0\u6c34\u3001\u9171\u6cb9\u548c\u7cd6\uff0c\u5927\u706b\u70e7\u5f00\u540e\u5c0f\u706b\u709630\u5206\u949f\u30025. \u5927\u706b\u6536\u6c41\u5373\u53ef\u3002","en","Ingredients: Chicken wings, potatoes, green peppers, green onions, ginger, garlic, soy sauce, cooking wine, sugar, cooking oil\nMethod: 1. Marinate chicken wings with cooking wine and soy sauce for 20 minutes, dice potatoes, cut green peppers into segments. 2. Heat oil in a pan, fry wings until golden. 3. Add green onions, ginger, and garlic, saut\xe9 until fragrant, then add potatoes and green peppers, stir-fry. 4. Add water, soy sauce, and sugar, bring to a boil, then simmer for 30 minutes. 5. Reduce sauce over high heat and serve."],a6,a6),98,h),A.E(a2,"scallion-oil-chicken",A.e(["zh","\u8471\u6cb9\u7116\u9e21","en","Scallion Oil Braised Chicken"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u817f\u8089\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u7cd6\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u817f\u8089\u5207\u5757\uff0c\u7528\u6599\u9152\u548c\u9171\u6cb9\u814c\u523615\u5206\u949f\u30022. \u8471\u5207\u6bb5\uff0c\u59dc\u5207\u7247\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u714e\u9e21\u8089\u81f3\u4e24\u9762\u91d1\u9ec4\u30024. \u52a0\u8471\u59dc\u7092\u9999\uff0c\u52a0\u5165\u9171\u6cb9\u548c\u7cd6\u8c03\u5473\u30025. \u52a0\u6c34\u5c0f\u706b\u7116\u716e20\u5206\u949f\uff0c\u5927\u706b\u6536\u6c41\u5373\u53ef\u3002","en","Ingredients: Chicken thigh, green onions, ginger, soy sauce, cooking wine, sugar, cooking oil\nMethod: 1. Cut chicken thigh into pieces, marinate with cooking wine and soy sauce for 15 minutes. 2. Cut green onions into segments, slice ginger. 3. Heat oil in a pan, fry chicken until golden on both sides. 4. Add green onions and ginger, saut\xe9 until fragrant, then add soy sauce and sugar. 5. Add water, simmer for 20 minutes, then reduce sauce over high heat and serve."],a6,a6),98,h),A.E("\ud83e\uddc8","fermented-bean-curd-chicken",A.e(["zh","\u5357\u4e73\u70b8\u9e21\u7fc5","en","Fermented Bean Curd Fried Chicken Wings"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u7fc5\u3001\u5357\u4e73\uff08\u7ea2\u8150\u4e73\uff09\u3001\u849c\u3001\u6599\u9152\u3001\u6dc0\u7c89\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u7fc5\u7528\u5357\u4e73\u3001\u6599\u9152\u548c\u849c\u672b\u814c\u52362\u5c0f\u65f6\u30022. \u88f9\u4e0a\u6dc0\u7c89\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u6cb9\u6e29\u516d\u6210\u70ed\u65f6\u653e\u5165\u9e21\u7fc5\u70b8\u81f3\u91d1\u9ec4\u9165\u8106\u30024. \u635e\u51fa\u63a7\u6cb9\u5373\u53ef\u3002","en","Ingredients: Chicken wings, fermented bean curd (red), garlic, cooking wine, cornstarch, cooking oil\nMethod: 1. Marinate chicken wings with fermented bean curd, cooking wine, and minced garlic for 2 hours. 2. Coat with cornstarch. 3. Heat oil in a pan to medium-high heat, fry wings until golden and crispy. 4. Drain oil and serve."],a6,a6),100,h),A.E(a3,"potato-tomato-chicken",A.e(["zh","\u571f\u8c46\u756a\u8304\u6cb9\u7116\u9e21","en","Braised Chicken with Potato and Tomato"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u817f\u8089\u3001\u571f\u8c46\u3001\u756a\u8304\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u7cd6\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u817f\u8089\u5207\u5757\uff0c\u7528\u9171\u6cb9\u814c\u523615\u5206\u949f\uff0c\u571f\u8c46\u548c\u756a\u8304\u5207\u5757\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u714e\u9e21\u8089\u81f3\u91d1\u9ec4\u30023. \u52a0\u8471\u59dc\u7092\u9999\uff0c\u653e\u5165\u571f\u8c46\u548c\u756a\u8304\u7ffb\u7092\u30024. \u52a0\u6c34\u548c\u7cd6\uff0c\u5927\u706b\u70e7\u5f00\u540e\u5c0f\u706b\u709630\u5206\u949f\u30025. \u5927\u706b\u6536\u6c41\u5373\u53ef\u3002","en","Ingredients: Chicken thigh, potatoes, tomatoes, green onions, ginger, soy sauce, sugar, cooking oil\nMethod: 1. Cut chicken thigh into pieces, marinate with soy sauce for 15 minutes, dice potatoes and tomatoes. 2. Heat oil in a pan, fry chicken until golden. 3. Add green onions and ginger, saut\xe9 until fragrant, then add potatoes and tomatoes, stir-fry. 4. Add water and sugar, bring to a boil, then simmer for 30 minutes. 5. Reduce sauce over high heat and serve."],a6,a6),92,h),A.E(g,"stir-fried-chicken",A.e(["zh","\u519c\u5bb6\u5c0f\u7092\u9e21","en","Stir-fried Chicken"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u8089\u3001\u9752\u6912\u3001\u7ea2\u6912\u3001\u5e72\u8fa3\u6912\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u8089\u5207\u5757\uff0c\u7528\u6599\u9152\u548c\u9171\u6cb9\u814c\u523615\u5206\u949f\u30022. \u9752\u6912\u548c\u7ea2\u6912\u5207\u4e1d\uff0c\u8471\u59dc\u849c\u5207\u672b\uff0c\u5e72\u8fa3\u6912\u526a\u6bb5\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7206\u9999\u8471\u59dc\u849c\u548c\u5e72\u8fa3\u6912\u30024. \u653e\u5165\u9e21\u8089\u7092\u81f3\u53d8\u8272\uff0c\u518d\u52a0\u5165\u9752\u7ea2\u6912\u4e1d\u7ffb\u7092\u30025. \u52a0\u76d0\u8c03\u5473\uff0c\u7092\u5300\u51fa\u9505\u3002","en","Ingredients: Chicken, green peppers, red peppers, dried chilies, green onions, ginger, garlic, soy sauce, cooking wine, salt, cooking oil\nMethod: 1. Cut chicken into pieces and marinate with cooking wine and soy sauce for 15 minutes. 2. Slice green and red peppers, mince green onions, ginger, and garlic, cut dried chilies into segments. 3. Heat oil in a pan, saut\xe9 green onions, ginger, garlic, and dried chilies. 4. Add chicken and stir-fry until it changes color, then add pepper slices and stir-fry. 5. Season with salt, stir well, and serve."],a6,a6),90,h),A.E(a1,"chicken-with-garlic-sauce",A.e(["zh","\u67f1\u4faf\u9171\u849c\u5934\u7092\u9e21","en","Chicken with Garlic and Sauce"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u8089\u3001\u5927\u849c\u3001\u67f1\u4faf\u9171\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u8089\u5207\u5757\uff0c\u7528\u9171\u6cb9\u814c\u523615\u5206\u949f\u30022. \u5927\u849c\u62cd\u788e\uff0c\u8471\u59dc\u5207\u672b\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u9e21\u8089\u81f3\u53d8\u8272\u30024. \u52a0\u8471\u59dc\u548c\u5927\u849c\u7092\u9999\uff0c\u653e\u5165\u67f1\u4faf\u9171\u7ffb\u7092\u5747\u5300\u30025. \u52a0\u5c11\u8bb8\u6c34\u7116\u716e5\u5206\u949f\u5373\u53ef\u3002","en","Ingredients: Chicken, garlic, Chu Hou sauce, green onions, ginger, soy sauce, cooking oil\nMethod: 1. Cut chicken into pieces, marinate with soy sauce for 15 minutes. 2. Crush garlic, mince green onions and ginger. 3. Heat oil in a pan, stir-fry chicken until it changes color. 4. Add green onions, ginger, and garlic, saut\xe9 until fragrant, then add Chu Hou sauce and stir-fry evenly. 5. Add a little water, simmer for 5 minutes, and serve."],a6,a6),80,h),A.E("\ud83c\udf72","yellow-braised-chicken",A.e(["zh","\u9ec4\u7116\u9e21","en","Yellow Braised Chicken"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u817f\u8089\u3001\u571f\u8c46\u3001\u9999\u83c7\u3001\u9752\u6912\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u7cd6\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u8089\u5207\u5757\uff0c\u7528\u6599\u9152\u548c\u9171\u6cb9\u814c\u523615\u5206\u949f\u30022. \u571f\u8c46\u5207\u5757\uff0c\u9999\u83c7\u6ce1\u53d1\u5207\u7247\uff0c\u9752\u6912\u5207\u6bb5\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u9e21\u8089\u81f3\u53d8\u8272\u30024. \u52a0\u8471\u59dc\u7092\u9999\uff0c\u653e\u5165\u571f\u8c46\u3001\u9999\u83c7\u548c\u9752\u6912\u30025. \u52a0\u6c34\u3001\u9171\u6cb9\u548c\u7cd6\uff0c\u5c0f\u706b\u711630\u5206\u949f\uff0c\u5927\u706b\u6536\u6c41\u5373\u53ef\u3002","en","Ingredients: Chicken thigh, potatoes, shiitake mushrooms, green peppers, green onions, ginger, soy sauce, cooking wine, sugar, cooking oil\nMethod: 1. Cut chicken into pieces, marinate with cooking wine and soy sauce for 15 minutes. 2. Dice potatoes, soak and slice shiitake mushrooms, cut green peppers into segments. 3. Heat oil in a pan, stir-fry chicken until it changes color. 4. Add green onions and ginger, saut\xe9 until fragrant, then add potatoes, mushrooms, and green peppers. 5. Add water, soy sauce, and sugar, simmer for 30 minutes, then reduce sauce over high heat and serve."],a6,a6),75,h),A.E(a4,"fried-chicken",A.e(["zh","\u849c\u9999/\u8702\u871c/\u7cd6\u918b\u70b8\u9e21","en","Fried Chicken (Garlic/Honey/Sweet & Sour)"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u7fc5\u6216\u9e21\u817f\u3001\u849c\uff08\u849c\u9999\uff09\u3001\u8702\u871c\uff08\u8702\u871c\uff09\u3001\u918b\u548c\u7cd6\uff08\u7cd6\u918b\uff09\u3001\u9762\u7c89\u3001\u6dc0\u7c89\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u8089\u7528\u76d0\u814c\u523620\u5206\u949f\u30022. \u9762\u7c89\u548c\u6dc0\u7c89\u8c03\u6210\u7cca\uff0c\u88f9\u5728\u9e21\u8089\u4e0a\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u70b8\u9e21\u8089\u81f3\u91d1\u9ec4\u9165\u8106\u30024. \u849c\u9999\uff1a\u7092\u849c\u672b\u6dcb\u4e0a\uff1b\u8702\u871c\uff1a\u5237\u8702\u871c\uff1b\u7cd6\u918b\uff1a\u7092\u918b\u548c\u7cd6\u6210\u9171\u6c41\u88f9\u4e0a\u30025. \u51fa\u9505\u98df\u7528\u3002","en","Ingredients: Chicken wings or thighs, garlic (garlic flavor), honey (honey flavor), vinegar and sugar (sweet & sour), flour, cornstarch, salt, cooking oil\nMethod: 1. Marinate chicken with salt for 20 minutes. 2. Mix flour and cornstarch into a batter, coat chicken. 3. Heat oil in a pan, fry chicken until golden and crispy. 4. Garlic: Saut\xe9 minced garlic and drizzle over; Honey: Brush with honey; Sweet & Sour: Stir-fry vinegar and sugar into a sauce and coat. 5. Serve."],a6,a6),88,h),A.E(a1,"garlic-chicken-breast",A.e(["zh","\u849c\u9999\u9e21\u80f8\u8089","en","Garlic Chicken Breast"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u80f8\u8089\u3001\u5927\u849c\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u80f8\u8089\u5207\u7247\uff0c\u7528\u9171\u6cb9\u548c\u6599\u9152\u814c\u523620\u5206\u949f\u30022. \u5927\u849c\u5207\u672b\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u714e\u9e21\u8089\u81f3\u4e24\u9762\u91d1\u9ec4\u30024. \u52a0\u849c\u672b\u7092\u9999\uff0c\u52a0\u76d0\u8c03\u5473\u30025. \u7092\u5300\u51fa\u9505\u5373\u53ef\u3002","en","Ingredients: Chicken breast, garlic, soy sauce, cooking wine, salt, cooking oil\nMethod: 1. Slice chicken breast, marinate with soy sauce and cooking wine for 20 minutes. 2. Mince garlic. 3. Heat oil in a pan, fry chicken until golden on both sides. 4. Add minced garlic and saut\xe9 until fragrant, season with salt. 5. Stir well and serve."],a6,a6),85,h),A.E(g,"dry-pot-chicken-wings",A.e(["zh","\u5e72\u9505\u9e21\u7fc5","en","Dry Pot Chicken Wings"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u7fc5\u3001\u5e72\u8fa3\u6912\u3001\u82b1\u6912\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u9171\u6cb9\u3001\u7cd6\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u7fc5\u7528\u9171\u6cb9\u814c\u523615\u5206\u949f\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u714e\u9e21\u7fc5\u81f3\u91d1\u9ec4\u30023. \u52a0\u5e72\u8fa3\u6912\u3001\u82b1\u6912\u3001\u8471\u59dc\u849c\u7092\u9999\u30024. \u52a0\u9171\u6cb9\u548c\u7cd6\u8c03\u5473\uff0c\u7ffb\u7092\u5747\u5300\u30025. \u5c0f\u706b\u71165\u5206\u949f\u5373\u53ef\u3002","en","Ingredients: Chicken wings, dried chilies, Sichuan peppercorns, green onions, ginger, garlic, soy sauce, sugar, cooking oil\nMethod: 1. Marinate chicken wings with soy sauce for 15 minutes. 2. Heat oil in a pan, fry wings until golden. 3. Add dried chilies, peppercorns, green onions, ginger, and garlic, saut\xe9 until fragrant. 4. Season with soy sauce and sugar, stir-fry evenly. 5. Simmer on low heat for 5 minutes and serve."],a6,a6),d,e),A.E("\ud83c\udf72","chongqing-chicken-pot",A.e(["zh","\u91cd\u5e86\u9e21\u516c\u7172","en","Chongqing Chicken Pot"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u8089\u3001\u571f\u8c46\u3001\u5e72\u8fa3\u6912\u3001\u82b1\u6912\u3001\u8c46\u74e3\u9171\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u9171\u6cb9\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u8089\u5207\u5757\uff0c\u7528\u9171\u6cb9\u814c\u523620\u5206\u949f\uff0c\u571f\u8c46\u5207\u5757\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u9e21\u8089\u81f3\u53d8\u8272\u30023. \u52a0\u5e72\u8fa3\u6912\u3001\u82b1\u6912\u548c\u8c46\u74e3\u9171\u7092\u9999\uff0c\u518d\u52a0\u8471\u59dc\u849c\u30024. \u653e\u5165\u571f\u8c46\uff0c\u52a0\u6c34\u709630\u5206\u949f\u30025. \u5927\u706b\u6536\u6c41\u5373\u53ef\u3002","en","Ingredients: Chicken, potatoes, dried chilies, Sichuan peppercorns, bean paste, green onions, ginger, garlic, soy sauce, cooking oil\nMethod: 1. Cut chicken into pieces, marinate with soy sauce for 20 minutes, dice potatoes. 2. Heat oil in a pan, stir-fry chicken until it changes color. 3. Add dried chilies, peppercorns, and bean paste, saut\xe9 until fragrant, then add green onions, ginger, and garlic. 4. Add potatoes and water, simmer for 30 minutes. 5. Reduce sauce over high heat and serve."],a6,a6),d,e),A.E("\ud83e\udd5c","kung-pao-chicken",A.e(["zh","\u5bab\u4fdd\u9e21\u4e01","en","Kung Pao Chicken"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e21\u80f8\u8089\u3001\u82b1\u751f\u7c73\u3001\u5e72\u8fa3\u6912\u3001\u82b1\u6912\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u9171\u6cb9\u3001\u7cd6\u3001\u918b\u3001\u6dc0\u7c89\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e21\u8089\u5207\u4e01\uff0c\u7528\u6dc0\u7c89\u548c\u9171\u6cb9\u814c\u523615\u5206\u949f\u30022. \u82b1\u751f\u7c73\u7092\u719f\u5907\u7528\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u9999\u5e72\u8fa3\u6912\u548c\u82b1\u6912\uff0c\u52a0\u8471\u59dc\u849c\u30024. \u653e\u5165\u9e21\u4e01\u7092\u81f3\u53d8\u8272\uff0c\u8c03\u9171\u6c41\uff08\u9171\u6cb9\u3001\u7cd6\u3001\u918b\uff09\u5012\u5165\u30025. \u52a0\u5165\u82b1\u751f\u7c73\u7092\u5300\u5373\u53ef\u3002","en","Ingredients: Chicken breast, peanuts, dried chilies, Sichuan peppercorns, green onions, ginger, garlic, soy sauce, sugar, vinegar, cornstarch, cooking oil\nMethod: 1. Dice chicken, marinate with cornstarch and soy sauce for 15 minutes. 2. Toast peanuts and set aside. 3. Heat oil in a pan, saut\xe9 dried chilies and peppercorns, add green onions, ginger, and garlic. 4. Add chicken and stir-fry until it changes color, pour in sauce (soy sauce, sugar, vinegar). 5. Add peanuts, stir well, and serve."],a6,a6),d,e)],a9),"chicken",p)
