o=A.dt(A.a([A.E(d,"beer-duck",A.e(["zh","\u5564\u9152\u9e2d","en","Beer Duck"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e2d\u8089\u3001\u5564\u9152\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u9171\u6cb9\u3001\u516b\u89d2\u3001\u5e72\u8fa3\u6912\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9e2d\u8089\u5207\u5757\u712f\u6c34\u53bb\u8165\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u9e2d\u8089\u81f3\u51fa\u6cb9\u30023. \u52a0\u8471\u59dc\u849c\u3001\u516b\u89d2\u548c\u5e72\u8fa3\u6912\u7092\u9999\u30024. \u5012\u5165\u5564\u9152\u548c\u9171\u6cb9\uff0c\u5927\u706b\u70e7\u5f00\u540e\u5c0f\u706b\u709640\u5206\u949f\u30025. \u5927\u706b\u6536\u6c41\u5373\u53ef\u3002","en","Ingredients: Duck, beer, green onions, ginger, garlic, soy sauce, star anise, dried chilies, cooking oil\nMethod: 1. Cut duck into pieces and blanch to remove odor. 2. Heat oil in a pan, stir-fry duck until oil renders. 3. Add green onions, ginger, garlic, star anise, and dried chilies, saut\xe9 until fragrant. 4. Pour in beer and soy sauce, bring to a boil, then simmer for 40 minutes. 5. Reduce sauce over high heat and serve."],a6,a6),d,e),A.E(d,"roast-duck",A.e(["zh","\u70e4\u9e2d","en","Roast Duck"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9e2d\u5b50\u3001\u8702\u871c\u3001\u9171\u6cb9\u3001\u4e94\u9999\u7c89\u3001\u6599\u9152\u3001\u8471\u3001\u59dc\n\u505a\u6cd5\uff1a1. \u9e2d\u5b50\u6d17\u51c0\uff0c\u7528\u9171\u6cb9\u3001\u4e94\u9999\u7c89\u548c\u6599\u9152\u814c\u5236\u4e00\u591c\u30022. \u70e4\u7bb1\u9884\u70ed180\u5ea6\uff0c\u9e2d\u5b50\u5237\u4e0a\u8702\u871c\u30023. \u653e\u5165\u70e4\u7bb1\u70e41.5\u5c0f\u65f6\uff0c\u6bcf20\u5206\u949f\u7ffb\u9762\u5e76\u5237\u871c\u6c41\u30024. \u70e4\u81f3\u76ae\u8106\u8089\u5ae9\uff0c\u5207\u7247\u642d\u914d\u8471\u4e1d\u98df\u7528\u3002","en","Ingredients: Duck, honey, soy sauce, five-spice powder, cooking wine, green onions, ginger\nMethod: 1. Clean duck and marinate with soy sauce, five-spice powder, and cooking wine overnight. 2. Preheat oven to 180\xb0C, brush duck with honey. 3. Roast in the oven for 1.5 hours, flipping and brushing with honey every 20 minutes. 4. Roast until skin is crispy and meat is tender, slice and serve with green onion shreds."],a6,a6),d,e)],a9),"duck",o)
