n=A.dt(A.a([A.E(a2,"stir-fried-lamb-scallion",A.e(["zh","\u8471\u7206\u7f8a\u8089","en","Stir-fried Lamb with Scallion"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u7f8a\u8089\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u7f8a\u8089\u5207\u8584\u7247\uff0c\u7528\u9171\u6cb9\u548c\u6599\u9152\u814c\u523615\u5206\u949f\u30022. \u8471\u5207\u6bb5\uff0c\u59dc\u5207\u4e1d\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7206\u9999\u59dc\u4e1d\u30024. \u653e\u5165\u7f8a\u8089\u5feb\u901f\u7ffb\u7092\u81f3\u53d8\u8272\u30025. \u52a0\u5165\u8471\u6bb5\u7ffb\u7092\u5747\u5300\uff0c\u52a0\u76d0\u8c03\u5473\u540e\u51fa\u9505\u3002","en","Ingredients: Lamb, green onions, ginger, soy sauce, cooking wine, salt, cooking oil\nMethod: 1. Slice lamb thinly and marinate with soy sauce and cooking wine for 15 minutes. 2. Cut green onions into segments, shred ginger. 3. Heat oil in a pan, saut\xe9 ginger. 4. Add lamb and stir-fry quickly until it changes color. 5. Add green onions, stir-fry evenly, season with salt, and serve."],a6,a6),95,h),A.E("\ud83d\udc11","cumin-lamb",A.e(["zh","\u5b5c\u7136\u7f8a\u8089","en","Cumin Lamb"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u7f8a\u8089\u3001\u5b5c\u7136\u7c89\u3001\u5e72\u8fa3\u6912\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u7f8a\u8089\u5207\u8584\u7247\uff0c\u7528\u9171\u6cb9\u814c\u523615\u5206\u949f\u30022. \u8471\u5207\u6bb5\uff0c\u59dc\u5207\u4e1d\uff0c\u5e72\u8fa3\u6912\u526a\u6bb5\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7206\u9999\u59dc\u4e1d\u548c\u5e72\u8fa3\u6912\u30024. \u653e\u5165\u7f8a\u8089\u7092\u81f3\u53d8\u8272\uff0c\u6492\u5165\u5b5c\u7136\u7c89\u7ffb\u7092\u5747\u5300\u30025. \u52a0\u76d0\u8c03\u5473\uff0c\u52a0\u5165\u8471\u6bb5\u7092\u5300\u540e\u51fa\u9505\u3002","en","Ingredients: Lamb, cumin powder, dried chilies, green onions, ginger, soy sauce, salt, cooking oil\nMethod: 1. Slice lamb thinly and marinate with soy sauce for 15 minutes. 2. Cut green onions into segments, shred ginger, cut dried chilies into segments. 3. Heat oil in a pan, saut\xe9 ginger and dried chilies. 4. Add lamb and stir-fry until it changes color, sprinkle with cumin powder and stir-fry evenly. 5. Season with salt, add green onions, stir well, and serve."],a6,a6),92,h),A.E(d,"french-lamb-stew",A.e(["zh","\u6cd5\u5f0f\u7096\u7f8a\u8089","en","French Lamb Stew"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u7f8a\u8089\u3001\u80e1\u841d\u535c\u3001\u571f\u8c46\u3001\u6d0b\u8471\u3001\u897f\u7ea2\u67ff\u3001\u7ea2\u9152\u3001\u8ff7\u8fed\u9999\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u7f8a\u8089\u5207\u5757\u712f\u6c34\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u7f8a\u8089\u81f3\u8868\u9762\u7126\u9ec4\u30023. \u52a0\u5165\u5207\u5757\u7684\u80e1\u841d\u535c\u3001\u571f\u8c46\u3001\u6d0b\u8471\u548c\u897f\u7ea2\u67ff\u7ffb\u7092\u30024. \u5012\u5165\u7ea2\u9152\uff0c\u52a0\u8ff7\u8fed\u9999\u548c\u76d0\u8c03\u5473\uff0c\u52a0\u6c34\u70961\u5c0f\u65f6\u30025. \u5927\u706b\u6536\u6c41\u5373\u53ef\u3002","en","Ingredients: Lamb, carrots, potatoes, onions, tomatoes, red wine, rosemary, salt, cooking oil\nMethod: 1. Cut lamb into chunks and blanch. 2. Heat oil in a pan, brown lamb on the surface. 3. Add diced carrots, potatoes, onions, and tomatoes, stir-fry. 4. Pour in red wine, season with rosemary and salt, add water and simmer for 1 hour. 5. Reduce sauce over high heat and serve."],a6,a6),d,e)],a9),"lamb",n)
