m=A.dt(A.a([A.E(f,"stir-fried-beef-cilantro",A.e(["zh","\u9999\u83dc\u7092\u725b\u8089","en","Stir-fried Beef with Cilantro"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u725b\u8089\u3001\u9999\u83dc\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u725b\u8089\u5207\u8584\u7247\uff0c\u7528\u9171\u6cb9\u548c\u6599\u9152\u814c\u523615\u5206\u949f\u30022. \u9999\u83dc\u6d17\u51c0\u5207\u6bb5\uff0c\u8471\u59dc\u849c\u5207\u672b\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7206\u9999\u8471\u59dc\u849c\u30024. \u653e\u5165\u725b\u8089\u5feb\u901f\u7ffb\u7092\u81f3\u53d8\u8272\u30025. \u52a0\u5165\u9999\u83dc\u7ffb\u7092\u5747\u5300\uff0c\u52a0\u76d0\u8c03\u5473\u540e\u51fa\u9505\u3002","en","Ingredients: Beef, cilantro, green onions, ginger, garlic, soy sauce, cooking wine, salt, cooking oil\nMethod: 1. Slice beef thinly and marinate with soy sauce and cooking wine for 15 minutes. 2. Rinse cilantro and cut into segments, mince green onions, ginger, and garlic. 3. Heat oil in a pan, saut\xe9 green onions, ginger, and garlic. 4. Add beef and stir-fry quickly until it changes color. 5. Add cilantro, stir-fry evenly, season with salt, and serve."],a6,a6),90,h),A.E(g,"stir-fried-beef-peppers",A.e(["zh","\u8fa3\u6912\u7092\u725b\u8089","en","Stir-fried Beef with Peppers"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u725b\u8089\u3001\u9752\u6912\u3001\u7ea2\u6912\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u6dc0\u7c89\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u725b\u8089\u5207\u4e1d\uff0c\u7528\u9171\u6cb9\u548c\u6dc0\u7c89\u814c\u523615\u5206\u949f\u30022. \u9752\u6912\u548c\u7ea2\u6912\u5207\u4e1d\uff0c\u8471\u59dc\u5207\u672b\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7206\u9999\u8471\u59dc\u30024. \u653e\u5165\u725b\u8089\u4e1d\u7092\u81f3\u53d8\u8272\uff0c\u518d\u52a0\u5165\u8fa3\u6912\u4e1d\u7ffb\u7092\u30025. \u52a0\u76d0\u8c03\u5473\uff0c\u7092\u5300\u540e\u51fa\u9505\u3002","en","Ingredients: Beef, green peppers, red peppers, green onions, ginger, soy sauce, cornstarch, salt, cooking oil\nMethod: 1. Shred beef and marinate with soy sauce and cornstarch for 15 minutes. 2. Shred green and red peppers, mince green onions and ginger. 3. Heat oil in a pan, saut\xe9 green onions and ginger. 4. Add beef shreds and stir-fry until they change color, then add pepper shreds and stir-fry. 5. Season with salt, stir well, and serve."],a6,a6),93,h),A.E(a3,"tomato-beef-tail",A.e(["zh","\u756a\u8304\u725b\u5c3e/\u725b\u8169\u7172","en","Tomato Beef Tail/Brisket Pot"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u725b\u5c3e\u6216\u725b\u8169\u3001\u756a\u8304\u3001\u6d0b\u8471\u3001\u80e1\u841d\u535c\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u7cd6\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u725b\u5c3e\u6216\u725b\u8169\u5207\u5757\uff0c\u712f\u6c34\u53bb\u8840\u6cab\u30022. \u756a\u8304\u5207\u5757\uff0c\u6d0b\u8471\u548c\u80e1\u841d\u535c\u5207\u4e01\uff0c\u8471\u59dc\u5207\u672b\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u9999\u8471\u59dc\uff0c\u653e\u5165\u725b\u8089\u7178\u7092\u81f3\u8868\u9762\u5fae\u7126\u30024. \u52a0\u5165\u756a\u8304\u3001\u6d0b\u8471\u548c\u80e1\u841d\u535c\u7ffb\u7092\uff0c\u52a0\u9171\u6cb9\u3001\u6599\u9152\u548c\u7cd6\u8c03\u5473\u30025. \u52a0\u6c34\u6ca1\u8fc7\u98df\u6750\uff0c\u5927\u706b\u70e7\u5f00\u540e\u5c0f\u706b\u70961.5\u5c0f\u65f6\uff0c\u52a0\u76d0\u8c03\u5473\u540e\u51fa\u9505\u3002","en","Ingredients: Beef tail or brisket, tomatoes, onion, carrots, green onions, ginger, soy sauce, cooking wine, sugar, salt, cooking oil\nMethod: 1. Cut beef tail or brisket into chunks and blanch to remove blood foam. 2. Dice tomatoes, onion, and carrots, mince green onions and ginger. 3. Heat oil in a pan, saut\xe9 green onions and ginger, then add beef and stir-fry until slightly browned. 4. Add tomatoes, onion, and carrots, stir-fry, and season with soy sauce, cooking wine, and sugar. 5. Add water to cover ingredients, bring to a boil, then simmer for 1.5 hours, season with salt, and serve."],a6,a6),95,h),A.E(d,"curry-beef-brisket",A.e(["zh","\u5496\u55b1\u725b\u8169","en","Curry Beef Brisket"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u725b\u8169\u3001\u571f\u8c46\u3001\u80e1\u841d\u535c\u3001\u6d0b\u8471\u3001\u5496\u55b1\u5757\u3001\u6930\u5976\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u725b\u8169\u5207\u5757\u712f\u6c34\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u6d0b\u8471\u81f3\u900f\u660e\uff0c\u52a0\u5165\u725b\u8169\u7092\u81f3\u8868\u9762\u7126\u9ec4\u30023. \u52a0\u571f\u8c46\u548c\u80e1\u841d\u535c\u5757\u7ffb\u7092\u30024. \u52a0\u5165\u5496\u55b1\u5757\u548c\u6930\u5976\uff0c\u52a0\u6c34\u709640\u5206\u949f\u30025. \u52a0\u76d0\u8c03\u5473\uff0c\u5927\u706b\u6536\u6c41\u5373\u53ef\u3002","en","Ingredients: Beef brisket, potatoes, carrots, onions, curry blocks, coconut milk, salt, cooking oil\nMethod: 1. Cut beef brisket into chunks and blanch. 2. Heat oil in a pan, saut\xe9 onions until translucent, add brisket and brown the surface. 3. Add potato and carrot chunks, stir-fry. 4. Add curry blocks and coconut milk, add water and simmer for 40 minutes. 5. Season with salt, reduce sauce over high heat, and serve."],a6,a6),d,h),A.E(a,"braised-beef",A.e(["zh","\u5364\u725b\u8089","en","Braised Beef"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u725b\u8171\u8089\u3001\u8471\u3001\u59dc\u3001\u516b\u89d2\u3001\u6842\u76ae\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u7cd6\u3001\u76d0\n\u505a\u6cd5\uff1a1. \u725b\u8089\u712f\u6c34\u53bb\u8840\u6cab\u30022. \u9505\u4e2d\u52a0\u6c34\uff0c\u653e\u5165\u8471\u59dc\u3001\u516b\u89d2\u3001\u6842\u76ae\u3001\u9171\u6cb9\u3001\u6599\u9152\u548c\u7cd6\u716e\u5f00\u30023. \u653e\u5165\u725b\u8089\uff0c\u5c0f\u706b\u70962\u5c0f\u65f6\u30024. \u52a0\u76d0\u8c03\u5473\uff0c\u7ee7\u7eed\u709630\u5206\u949f\u30025. \u635e\u51fa\u653e\u51c9\u5207\u7247\u5373\u53ef\u3002","en","Ingredients: Beef shank, green onions, ginger, star anise, cinnamon, soy sauce, cooking wine, sugar, salt\nMethod: 1. Blanch beef to remove blood foam. 2. Add water to a pot with green onions, ginger, star anise, cinnamon, soy sauce, cooking wine, and sugar, bring to a boil. 3. Add beef and simmer for 2 hours. 4. Season with salt and simmer for another 30 minutes. 5. Remove, cool, and slice to serve."],a6,a6),93,h),A.E(a,"cold-braised-beef",A.e(["zh","\u51c9\u62cc\u5364\u725b\u8089","en","Cold Braised Beef"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u5364\u725b\u8089\u3001\u9999\u83dc\u3001\u8471\u3001\u82b1\u6912\u6cb9\u3001\u9171\u6cb9\u3001\u918b\u3001\u7cd6\u3001\u8fa3\u6912\u6cb9\n\u505a\u6cd5\uff1a1. \u5364\u725b\u8089\u5207\u8584\u7247\uff0c\u9999\u83dc\u548c\u8471\u5207\u6bb5\u30022. \u8c03\u9171\u6c41\uff1a\u9171\u6cb9\u3001\u918b\u3001\u7cd6\u3001\u82b1\u6912\u6cb9\u548c\u8fa3\u6912\u6cb9\u62cc\u5300\u30023. \u5c06\u9171\u6c41\u5012\u5165\u725b\u8089\u4e2d\u62cc\u5300\u30024. \u6492\u4e0a\u9999\u83dc\u548c\u8471\u6bb5\u5373\u53ef\u3002","en","Ingredients: Braised beef, cilantro, green onions, Sichuan pepper oil, soy sauce, vinegar, sugar, chili oil\nMethod: 1. Slice braised beef thinly, cut cilantro and green onions into segments. 2. Mix sauce: soy sauce, vinegar, sugar, Sichuan pepper oil, and chili oil. 3. Pour sauce over beef and mix well. 4. Sprinkle with cilantro and green onions and serve."],a6,a6),92,h),A.E(a1,"stir-fried-braised-beef-garlic",A.e(["zh","\u5364\u725b\u8089\u7092\u849c\u82d7","en","Stir-fried Braised Beef with Garlic Sprouts"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u5364\u725b\u8089\u3001\u849c\u82d7\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u5364\u725b\u8089\u5207\u7247\uff0c\u849c\u82d7\u5207\u6bb5\uff0c\u8471\u59dc\u5207\u672b\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7206\u9999\u8471\u59dc\u30023. \u653e\u5165\u725b\u8089\u7ffb\u7092\uff0c\u518d\u52a0\u5165\u849c\u82d7\u5feb\u901f\u7092\u5300\u30024. \u52a0\u9171\u6cb9\u8c03\u5473\uff0c\u51fa\u9505\u5373\u53ef\u3002","en","Ingredients: Braised beef, garlic sprouts, green onions, ginger, soy sauce, cooking oil\nMethod: 1. Slice braised beef, cut garlic sprouts into segments, mince green onions and ginger. 2. Heat oil in a pan, saut\xe9 green onions and ginger. 3. Add beef and stir-fry, then add garlic sprouts and stir-fry quickly. 4. Season with soy sauce and serve."],a6,a6),94,h),A.E(b,"honey-pepper-beef",A.e(["zh","\u871c\u6c41\u6912\u9999\u725b\u8089\u7c92","en","Honey Pepper Beef Cubes"],a6,a6),A.e(["zh","1.5\u9171\u6cb9 2\u8702\u871c\ud83d\ude0b","en","1.5 soy sauce, 2 honey"],a6,a6),96,h),A.E(d,"boiled-beef",A.e(["zh","\u6c34\u716e\u725b\u8089","en","Boiled Beef"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u725b\u8089\u3001\u8c46\u82bd\u3001\u5e72\u8fa3\u6912\u3001\u82b1\u6912\u3001\u8471\u3001\u59dc\u3001\u849c\u3001\u8c46\u74e3\u9171\u3001\u9171\u6cb9\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u725b\u8089\u5207\u8584\u7247\uff0c\u7528\u6dc0\u7c89\u548c\u9171\u6cb9\u814c\u523615\u5206\u949f\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u9999\u8c46\u74e3\u9171\u3001\u5e72\u8fa3\u6912\u548c\u82b1\u6912\u30023. \u52a0\u6c34\u716e\u5f00\uff0c\u4e0b\u8c46\u82bd\u716e\u719f\u635e\u51fa\u57ab\u5e95\u30024. \u4e0b\u725b\u8089\u716e\u81f3\u53d8\u8272\uff0c\u6dcb\u4e0a\u70ed\u6cb9\u548c\u8471\u82b1\u5373\u53ef\u3002","en","Ingredients: Beef, bean sprouts, dried chilies, Sichuan peppercorns, green onions, ginger, garlic, bean paste, soy sauce, cooking oil\nMethod: 1. Slice beef thinly, marinate with cornstarch and soy sauce for 15 minutes. 2. Heat oil in a pan, saut\xe9 bean paste, dried chilies, and peppercorns. 3. Add water and bring to a boil, cook bean sprouts and remove to serve as a base. 4. Add beef and cook until it changes color, drizzle with hot oil and green onions, and serve."],a6,a6),d,h),A.E(d,"stir-fried-beef-potato",A.e(["zh","\u571f\u8c46\u7092\u725b\u8089","en","Stir-fried Beef with Potato"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u725b\u8089\u3001\u571f\u8c46\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u725b\u8089\u5207\u7247\uff0c\u7528\u9171\u6cb9\u814c\u523615\u5206\u949f\uff0c\u571f\u8c46\u5207\u7247\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u725b\u8089\u81f3\u53d8\u8272\uff0c\u76db\u51fa\u30023. \u52a0\u8471\u59dc\u7092\u9999\uff0c\u653e\u5165\u571f\u8c46\u7247\u7092\u81f3\u534a\u719f\u30024. \u56de\u9505\u725b\u8089\uff0c\u52a0\u76d0\u8c03\u5473\uff0c\u7092\u5300\u5373\u53ef\u3002","en","Ingredients: Beef, potatoes, green onions, ginger, soy sauce, salt, cooking oil\nMethod: 1. Slice beef and marinate with soy sauce for 15 minutes, slice potatoes. 2. Heat oil in a pan, stir-fry beef until it changes color, then remove. 3. Saut\xe9 green onions and ginger, add potato slices and cook until half-done. 4. Return beef to the pan, season with salt, stir well, and serve."],a6,a6),d,c),A.E(d,"stir-fried-beef-pepper-shreds",A.e(["zh","\u9752\u6912\u725b\u8089\u4e1d","en","Stir-fried Beef Shreds with Peppers"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u725b\u8089\u3001\u9752\u6912\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u6dc0\u7c89\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u725b\u8089\u5207\u4e1d\uff0c\u7528\u9171\u6cb9\u548c\u6dc0\u7c89\u814c\u523615\u5206\u949f\u30022. \u9752\u6912\u5207\u4e1d\uff0c\u8471\u59dc\u5207\u672b\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7206\u9999\u8471\u59dc\u30024. \u653e\u5165\u725b\u8089\u4e1d\u7092\u81f3\u53d8\u8272\uff0c\u518d\u52a0\u9752\u6912\u4e1d\u7ffb\u7092\u30025. \u52a0\u76d0\u8c03\u5473\uff0c\u51fa\u9505\u5373\u53ef\u3002","en","Ingredients: Beef, green peppers, green onions, ginger, soy sauce, cornstarch, cooking oil\nMethod: 1. Shred beef and marinate with soy sauce and cornstarch for 15 minutes. 2. Shred green peppers, mince green onions and ginger. 3. Heat oil in a pan, saut\xe9 green onions and ginger. 4. Add beef shreds and stir-fry until they change color, then add pepper shreds and stir-fry. 5. Season with salt and serve."],a6,a6),d,e),A.E(d,"black-pepper-beef",A.e(["zh","\u9ed1\u6912\u725b\u8089\u7c92","en","Black Pepper Beef Cubes"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u725b\u8089\u3001\u9ed1\u80e1\u6912\u7c89\u3001\u6d0b\u8471\u3001\u9752\u6912\u3001\u9171\u6cb9\u3001\u7cd6\u3001\u6dc0\u7c89\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u725b\u8089\u5207\u4e01\uff0c\u7528\u9171\u6cb9\u548c\u6dc0\u7c89\u814c\u523620\u5206\u949f\u30022. \u6d0b\u8471\u548c\u9752\u6912\u5207\u5757\u30023. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u725b\u8089\u81f3\u53d8\u8272\uff0c\u76db\u51fa\u30024. \u52a0\u6d0b\u8471\u548c\u9752\u6912\u7092\u8f6f\uff0c\u653e\u5165\u725b\u8089\u30025. \u52a0\u9ed1\u80e1\u6912\u7c89\u548c\u7cd6\u8c03\u5473\uff0c\u7092\u5300\u5373\u53ef\u3002","en","Ingredients: Beef, black pepper powder, onion, green pepper, soy sauce, sugar, cornstarch, cooking oil\nMethod: 1. Dice beef and marinate with soy sauce and cornstarch for 20 minutes. 2. Dice onion and green pepper. 3. Heat oil in a pan, stir-fry beef until it changes color, then remove. 4. Saut\xe9 onion and green pepper until soft, add beef back. 5. Season with black pepper and sugar, stir well, and serve."],a6,a6),d,e)],a9),"beef",m)
