o=A.n5("staples",k,A.a([m,n,A.dt(A.a([A.E("\ud83e\udd6f","stir-fried-bread",A.e(["zh","\u7092\u997c","en","Stir-fried Bread"],a6,a6),A.w(a6,a6),90,h),A.E(d,"scallion-pancake",A.e(["zh","\u624b\u6293\u997c","en","Scallion Pancake"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9762\u7c89\u3001\u6c34\u3001\u8471\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9762\u7c89\u52a0\u6c34\u548c\u5c11\u8bb8\u76d0\u63c9\u6210\u9762\u56e2\uff0c\u919230\u5206\u949f\u30022. \u64c0\u6210\u8584\u7247\uff0c\u5237\u6cb9\u6492\u4e0a\u8471\u82b1\uff0c\u5377\u8d77\u518d\u64c0\u5e73\u30023. \u70ed\u5e73\u5e95\u9505\u52a0\u6cb9\uff0c\u653e\u5165\u9762\u997c\u714e\u81f3\u4e24\u9762\u91d1\u9ec4\u30024. \u714e\u597d\u540e\u7528\u624b\u6293\u677e\u30025. \u51fa\u9505\u540e\u5373\u53ef\u98df\u7528\u3002","en","Ingredients: Flour, water, green onions, salt, cooking oil\nMethod: 1. Mix flour with water and a pinch of salt to form a dough, let rest for 30 minutes. 2. Roll out into a thin sheet, brush with oil, sprinkle with chopped green onions, roll up, and flatten again. 3. Heat oil in a flat pan, fry the pancake until golden on both sides. 4. After frying, scrunch with hands to loosen. 5. Serve immediately."],a6,a6),d,h),A.E(d,"egg-pancake",A.e(["zh","\u9e21\u86cb\u704c\u997c","en","Egg Pancake"],a6,a6),A.e(["zh","\u597d\u4e45\u6ca1\u505a\u4e86\uff0c\u6211\u8fd8\u8bb0\u5f97\u4e48\ud83e\udd14","en","Haven't made it for a while, do I still remember?"],a6,a6),d,h),A.E("\ud83e\udd5a","plain-egg-pancake",A.e(["zh","\u9e21\u86cb\u997c","en","Plain Egg Pancake"],a6,a6),A.w(a6,a6),92,h),A.E("\ud83e\udd6f","sauce-pancake",A.e(["zh","\u9171\u9999\u997c","en","Sauce Pancake"],a6,a6),A.w(a6,a6),93,h),A.E(d,"chinese-hamburger",A.e(["zh","\u8089\u5939\u998d","en","Chinese Hamburger"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9762\u7c89\u3001\u732a\u8089\u3001\u8471\u3001\u59dc\u3001\u516b\u89d2\u3001\u9171\u6cb9\u3001\u6599\u9152\u3001\u7cd6\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9762\u7c89\u52a0\u6c34\u63c9\u6210\u9762\u56e2\uff0c\u53d1\u9175\u540e\u64c0\u6210\u997c\uff0c\u70e4\u81f3\u91d1\u9ec4\u30022. \u732a\u8089\u5207\u5757\u712f\u6c34\uff0c\u70ed\u9505\u52a0\u6cb9\u7092\u81f3\u8868\u9762\u7126\u9ec4\u30023. \u52a0\u8471\u59dc\u3001\u516b\u89d2\u3001\u9171\u6cb9\u3001\u6599\u9152\u548c\u7cd6\uff0c\u52a0\u6c34\u70961\u5c0f\u65f6\u30024. \u7096\u597d\u7684\u8089\u5241\u788e\uff0c\u5939\u5165\u70e4\u597d\u7684\u997c\u4e2d\u30025. \u51fa\u9505\u540e\u98df\u7528\u3002","en","Ingredients: Flour, pork, green onions, ginger, star anise, soy sauce, cooking wine, sugar, cooking oil\nMethod: 1. Mix flour with water to form a dough, ferment, roll into flatbreads, and bake until golden. 2. Cut pork into chunks, blanch, then fry in a heated pan with oil until browned. 3. Add green onions, ginger, star anise, soy sauce, cooking wine, and sugar, cover with water and braise for 1 hour. 4. Chop braised pork and stuff into baked flatbreads. 5. Serve immediately."],a6,a6),d,e),A.E(d,"pork-fillet-bun",A.e(["zh","\u91cc\u810a\u5939\u998d","en","Pork Fillet Bun"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9762\u7c89\u3001\u732a\u91cc\u810a\u8089\u3001\u9762\u7c89\u3001\u6dc0\u7c89\u3001\u9e21\u86cb\u3001\u8471\u3001\u9171\u6cb9\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9762\u7c89\u52a0\u6c34\u63c9\u6210\u9762\u56e2\uff0c\u53d1\u9175\u540e\u64c0\u6210\u997c\uff0c\u70e4\u81f3\u91d1\u9ec4\u30022. \u732a\u91cc\u810a\u5207\u6761\uff0c\u7528\u9171\u6cb9\u814c\u523620\u5206\u949f\u30023. \u9762\u7c89\u3001\u6dc0\u7c89\u548c\u9e21\u86cb\u8c03\u6210\u7cca\uff0c\u88f9\u5728\u8089\u6761\u4e0a\u30024. \u70ed\u9505\u52a0\u6cb9\uff0c\u70b8\u8089\u6761\u81f3\u91d1\u9ec4\u9165\u8106\u30025. \u70b8\u597d\u7684\u8089\u5939\u5165\u997c\u4e2d\uff0c\u6492\u4e0a\u8471\u82b1\u98df\u7528\u3002","en","Ingredients: Flour, pork tenderloin, flour, cornstarch, egg, green onions, soy sauce, salt, cooking oil\nMethod: 1. Mix flour with water to form a dough, ferment, roll into flatbreads, and bake until golden. 2. Cut pork tenderloin into strips, marinate with soy sauce for 20 minutes. 3. Mix flour, cornstarch, and egg into a batter, coat pork strips. 4. Heat oil in a pan, fry pork strips until golden and crispy. 5. Place fried pork in the flatbreads, sprinkle with green onions, and serve."],a6,a6),d,e),A.E(d,"beef-pie",A.e(["zh","\u725b\u8089\u9985\u997c","en","Beef Pie"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9762\u7c89\u3001\u725b\u8089\u672b\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9762\u7c89\u52a0\u6c34\u63c9\u6210\u9762\u56e2\uff0c\u919230\u5206\u949f\u30022. \u725b\u8089\u672b\u52a0\u8471\u59dc\u672b\u3001\u9171\u6cb9\u548c\u76d0\u62cc\u5300\u30023. \u9762\u56e2\u5206\u6210\u5c0f\u4efd\uff0c\u64c0\u6210\u5706\u76ae\u5305\u5165\u725b\u8089\u9985\u30024. \u70ed\u5e73\u5e95\u9505\u52a0\u6cb9\uff0c\u714e\u9985\u997c\u81f3\u4e24\u9762\u91d1\u9ec4\u30025. \u51fa\u9505\u540e\u98df\u7528\u3002","en","Ingredients: Flour, ground beef, green onions, ginger, soy sauce, salt, cooking oil\nMethod: 1. Mix flour with water to form a dough, let rest for 30 minutes. 2. Mix ground beef with minced green onions, ginger, soy sauce, and salt. 3. Divide dough into small portions, roll into rounds, and fill with beef mixture. 4. Heat oil in a flat pan, fry pies until golden on both sides. 5. Serve immediately."],a6,a6),d,e),A.E(d,"meat-pancake",A.e(["zh","\u9c9c\u8089\u9505\u76d4","en","Meat Pancake"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9762\u7c89\u3001\u732a\u8089\u672b\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9762\u7c89\u52a0\u6c34\u63c9\u6210\u9762\u56e2\uff0c\u919230\u5206\u949f\u30022. \u732a\u8089\u672b\u52a0\u8471\u59dc\u672b\u3001\u9171\u6cb9\u548c\u76d0\u62cc\u5300\u30023. \u9762\u56e2\u64c0\u6210\u5927\u5706\u76ae\uff0c\u62b9\u6cb9\u6492\u8089\u9985\uff0c\u5377\u8d77\u538b\u6241\u30024. \u70ed\u5e73\u5e95\u9505\u52a0\u6cb9\uff0c\u714e\u81f3\u4e24\u9762\u91d1\u9ec4\u9165\u8106\u30025. \u51fa\u9505\u540e\u98df\u7528\u3002","en","Ingredients: Flour, ground pork, green onions, ginger, soy sauce, salt, cooking oil\nMethod: 1. Mix flour with water to form a dough, let rest for 30 minutes. 2. Mix ground pork with minced green onions, ginger, soy sauce, and salt. 3. Roll dough into a large round, spread with oil and meat filling, roll up and flatten. 4. Heat oil in a flat pan, fry until golden and crispy on both sides. 5. Serve immediately."],a6,a6),d,e),A.E(d,"beef-dumplings",A.e(["zh","\u725b\u8089\u9505\u8d34","en","Beef Dumplings"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9762\u7c89\u3001\u725b\u8089\u672b\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9762\u7c89\u52a0\u6c34\u63c9\u6210\u9762\u56e2\uff0c\u919230\u5206\u949f\u30022. \u725b\u8089\u672b\u52a0\u8471\u59dc\u672b\u3001\u9171\u6cb9\u548c\u76d0\u62cc\u5300\u30023. \u9762\u56e2\u5206\u6210\u5c0f\u4efd\uff0c\u64c0\u6210\u5706\u76ae\u5305\u5165\u725b\u8089\u9985\u30024. \u70ed\u5e73\u5e95\u9505\u52a0\u6cb9\uff0c\u653e\u5165\u9505\u8d34\u714e\u81f3\u5e95\u90e8\u91d1\u9ec4\uff0c\u52a0\u6c34\u76d6\u76d6\u71165\u5206\u949f\u30025. \u6c34\u5206\u6536\u5e72\u540e\u51fa\u9505\u98df\u7528\u3002","en","Ingredients: Flour, ground beef, green onions, ginger, soy sauce, salt, cooking oil\nMethod: 1. Mix flour with water to form a dough, let rest for 30 minutes. 2. Mix ground beef with minced green onions, ginger, soy sauce, and salt. 3. Divide dough into small portions, roll into rounds, and fill with beef mixture. 4. Heat oil in a flat pan, fry dumplings until bottoms are golden, add water, cover, and steam for 5 minutes. 5. Serve once water evaporates."],a6,a6),d,e)],a9),"bread",o)],i))
