m=A.n5("soup",n,A.a([A.dt(A.a([A.E(a0,"yam-corn-ribs-soup",A.e(["zh","\u5c71\u836f\u7389\u7c73\u6392\u9aa8\u6c64","en","Yam, Corn and Ribs Soup"],a6,a6),A.w(a6,a6),94,h),A.E(a0,"corn-chicken-soup",A.e(["zh","\u7389\u7c73\u9e21\u6c64","en","Corn and Chicken Soup"],a6,a6),A.w(a6,a6),92,h),A.E(d,"tomato-egg-soup",A.e(["zh","\u756a\u8304\u86cb\u6c64","en","Tomato and Egg Soup"],a6,a6),A.e(["zh","\u6696\u6696\u7684\uff0c\u597d\u559d\ud83d\ude0b","en","Warm and delicious"],a6,a6),d,h),A.E(d,"rice-congee",A.e(["zh","\u7c73\u7ca5","en","Rice Congee"],a6,a6),A.w(a6,a6),d,h),A.E(d,"vermicelli-cabbage-beef-ball-soup",A.e(["zh","\u7c89\u4e1d\u767d\u83dc\u725b\u8089\u4e38\u6c64","en","Vermicelli, Cabbage and Beef Ball Soup"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u7c89\u4e1d\u3001\u767d\u83dc\u3001\u725b\u8089\u4e38\u3001\u8471\u3001\u59dc\u3001\u9171\u6cb9\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u7c89\u4e1d\u6ce1\u8f6f\uff0c\u767d\u83dc\u5207\u6bb5\uff0c\u725b\u8089\u4e38\u5907\u597d\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7206\u9999\u8471\u59dc\u30023. \u52a0\u6c34\u716e\u5f00\uff0c\u653e\u5165\u725b\u8089\u4e38\u716e5\u5206\u949f\u30024. \u52a0\u5165\u767d\u83dc\u548c\u7c89\u4e1d\uff0c\u518d\u716e3\u5206\u949f\u30025. \u52a0\u9171\u6cb9\u548c\u76d0\u8c03\u5473\u540e\u51fa\u9505\u3002","en","Ingredients: Vermicelli, cabbage, beef balls, green onions, ginger, soy sauce, salt, cooking oil\nMethod: 1. Soak vermicelli until soft, cut cabbage into segments, prepare beef balls. 2. Heat oil in a pot, saut\xe9 green onions and ginger. 3. Add water and bring to a boil, add beef balls and cook for 5 minutes. 4. Add cabbage and vermicelli, cook for another 3 minutes. 5. Season with soy sauce and salt, then serve."],a6,a6),d,e),A.E(d,"tomato-egg-dough-soup",A.e(["zh","\u756a\u8304\u9e21\u86cb\u7599\u7629\u6c64","en","Tomato and Egg Dough Soup"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u9762\u7c89\u3001\u756a\u8304\u3001\u9e21\u86cb\u3001\u8471\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u9762\u7c89\u52a0\u6c34\u8c03\u6210\u9762\u7599\u7629\uff0c\u756a\u8304\u5207\u5757\uff0c\u9e21\u86cb\u6253\u6563\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u756a\u8304\u81f3\u51fa\u6c41\uff0c\u52a0\u6c34\u716e\u5f00\u30023. \u4e0b\u5165\u9762\u7599\u7629\uff0c\u716e\u81f3\u6d6e\u8d77\u30024. \u5012\u5165\u86cb\u6db2\uff0c\u6405\u62cc\u6210\u86cb\u82b1\uff0c\u52a0\u76d0\u8c03\u5473\u30025. \u6492\u4e0a\u8471\u82b1\u540e\u51fa\u9505\u3002","en","Ingredients: Flour, tomatoes, eggs, green onions, salt, cooking oil\nMethod: 1. Mix flour with water to form dough lumps, dice tomatoes, beat eggs. 2. Heat oil in a pot, saut\xe9 tomatoes until juicy, add water and bring to a boil. 3. Add dough lumps, cook until they float. 4. Pour in egg mixture, stir into egg flowers, season with salt. 5. Sprinkle with green onions and serve."],a6,a6),d,e),A.E(d,"lamb-soup",A.e(["zh","\u7f8a\u8089\u6c64","en","Lamb Soup"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u7f8a\u8089\u3001\u8471\u3001\u59dc\u3001\u767d\u841d\u535c\u3001\u516b\u89d2\u3001\u76d0\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u7f8a\u8089\u5207\u5757\u712f\u6c34\u53bb\u8840\u6cab\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u8471\u59dc\u548c\u516b\u89d2\uff0c\u653e\u5165\u7f8a\u8089\u7178\u7092\u30023. \u52a0\u6c34\u716e\u5f00\uff0c\u5c0f\u706b\u70961.5\u5c0f\u65f6\u30024. \u52a0\u5165\u767d\u841d\u535c\u5757\uff0c\u518d\u716e20\u5206\u949f\u30025. \u52a0\u76d0\u8c03\u5473\u540e\u51fa\u9505\u3002","en","Ingredients: Lamb, green onions, ginger, white radish, star anise, salt, cooking oil\nMethod: 1. Cut lamb into chunks and blanch to remove blood foam. 2. Heat oil in a pot, saut\xe9 green onions, ginger, and star anise, add lamb and stir-fry. 3. Add water, bring to a boil, simmer for 1.5 hours. 4. Add white radish chunks, cook for another 20 minutes. 5. Season with salt and serve."],a6,a6),d,e),A.E(d,"hot-sour-soup",A.e(["zh","\u9178\u8fa3\u6c64","en","Hot and Sour Soup"],a6,a6),A.e(["zh","\u914d\u6599\uff1a\u6728\u8033\u3001\u8c46\u8150\u3001\u732a\u8089\u4e1d\u3001\u9e21\u86cb\u3001\u918b\u3001\u80e1\u6912\u7c89\u3001\u9171\u6cb9\u3001\u6dc0\u7c89\u3001\u98df\u7528\u6cb9\n\u505a\u6cd5\uff1a1. \u6728\u8033\u6ce1\u53d1\u5207\u4e1d\uff0c\u8c46\u8150\u5207\u6761\uff0c\u732a\u8089\u5207\u4e1d\u814c\u5236\u30022. \u70ed\u9505\u52a0\u6cb9\uff0c\u7092\u8089\u4e1d\u81f3\u53d8\u8272\uff0c\u52a0\u5165\u6728\u8033\u548c\u8c46\u8150\u30023. \u52a0\u6c34\u716e\u5f00\uff0c\u8c03\u5165\u918b\u3001\u80e1\u6912\u7c89\u548c\u9171\u6cb9\u30024. \u6dc0\u7c89\u52a0\u6c34\u52fe\u82a1\uff0c\u5012\u5165\u86cb\u6db2\u6210\u86cb\u82b1\u30025. \u716e1\u5206\u949f\u540e\u51fa\u9505\u3002","en","Ingredients: Wood ear mushrooms, tofu, pork shreds, egg, vinegar, white pepper, soy sauce, cornstarch, cooking oil\nMethod: 1. Soak and shred wood ear mushrooms, cut tofu into strips, marinate pork shreds. 2. Heat oil in a pot, stir-fry pork until it changes color, add wood ear and tofu. 3. Add water and bring to a boil, season with vinegar, white pepper, and soy sauce. 4. Thicken with cornstarch slurry, pour in egg to form egg flowers. 5. Cook for 1 minute and serve."],a6,a6),d,e)],a9),"soup-congee",m)],i))
